from source import find_in_sorted

def test_find_in_sorted_last_element():
    arr = [3, 4, 5, 6, 7]
    x = 7
    with pytest.raises(RecursionError):
        find_in_sorted(arr, x)
    # Now test the same case with a fixed version of the code
    def fixed_find_in_sorted(arr, x):
        def binsearch(start, end):
            if start == end:
                return -1
            mid = start + (end - start) // 2
            if x < arr[mid]:
                return binsearch(start, mid)
            elif x > arr[mid]:
                return binsearch(mid + 1, end)
            else:
                return mid

        return binsearch(0, len(arr))
    assert fixed_find_in_sorted(arr, x) == 4, f"Expected find_in_sorted({arr}, {x}) to return 4, but got {fixed_find_in_sorted(arr, x)}"
